module binary_decoder (
    input [1:0] obf_in,
    output [3:0] out
);

    // 2-bit binary decoder logic
    assign out = (obf_in == 2'b00) ? 4'b0001 :
                 (obf_in == 2'b01) ? 4'b0010 :
                 (obf_in == 2'b10) ? 4'b0100 :
                                 4'b1000;

endmodule
